import UIKit
import Foundation

func fetchFirstImage(urls: [URL]) async throws -> UIImage? {
    try await withThrowingTaskGroup(of: UIImage?.self) { group in
        for url in urls {
            group.addTask {
                let (data, _) = try await URLSession.shared.data(from: url)
                return UIImage(data: data)
            }
        }
        for try await image in group {
            if let img = image {
                group.cancelAll()
                return img
            }
        }
        return nil
    }
}

import Foundation

struct AsyncFileLines: AsyncSequence {
    typealias Element = String
    let url: URL
    func makeAsyncIterator() -> AsyncIterator { AsyncIterator(url: url) }
    struct AsyncIterator: AsyncIteratorProtocol {
        let url: URL
        var file: FileHandle?
        var buffer = Data()
        init(url: URL) {
            self.url = url
            self.file = try? FileHandle(forReadingFrom: url)
        }
        mutating func next() async throws -> String? {
            while true {
                if let range = buffer.range(of: Data([0x0A])) {
                    let line = buffer.subdata(in: 0..<range.lowerBound)
                    buffer.removeSubrange(0...range.lowerBound)
                    return String(data: line, encoding: .utf8)
                }
                guard let chunk = try await file?.read(upToCount: 4096), !chunk.isEmpty else {
                    if !buffer.isEmpty {
                        let line = String(data: buffer, encoding: .utf8)
                        buffer.removeAll()
                        return line
                    }
                    return nil
                }
                buffer.append(chunk)
            }
        }
    }
}

