import Foundation

struct NotificationAsyncSequence: AsyncSequence {
    typealias Element = Notification
    let name: Notification.Name
    let center: NotificationCenter
    func makeAsyncIterator() -> AsyncIterator { AsyncIterator(name: name, center: center) }
    struct AsyncIterator: AsyncIteratorProtocol {
        let name: Notification.Name
        let center: NotificationCenter
        var continuation: AsyncStream<Notification>.Iterator?
        init(name: Notification.Name, center: NotificationCenter) {
            let stream = AsyncStream<Notification> { continuation in
                let observer = center.addObserver(forName: name, object: nil, queue: nil) { notification in
                    continuation.yield(notification)
                }
                continuation.onTermination = { _ in
                    center.removeObserver(observer)
                }
            }
            self.continuation = stream.makeAsyncIterator()
        }
        mutating func next() async -> Notification? {
            await continuation?.next()
        }
    }
}

import Foundation

func squareConcurrently(_ numbers: [Int]) async -> [Int] {
    await withTaskGroup(of: (Int, Int).self) { group in
        for (i, n) in numbers.enumerated() {
            group.addTask { (i, n * n) }
        }
        var results = Array(repeating: 0, count: numbers.count)
        for await (i, squared) in group {
            results[i] = squared
        }
        return results
    }
}

