import CoreLocation

struct LocationStream: AsyncSequence {
    typealias Element = CLLocation
    func makeAsyncIterator() -> Iterator { Iterator() }
    struct Iterator: AsyncIteratorProtocol {
        let manager = CLLocationManager()
        let stream: AsyncStream<CLLocation>
        var iterator: AsyncStream<CLLocation>.Iterator
        init() {
            var continuation: AsyncStream<CLLocation>.Continuation!
            stream = AsyncStream { c in
                continuation = c
            }
            iterator = stream.makeAsyncIterator()
            manager.requestWhenInUseAuthorization()
            manager.startUpdatingLocation()
            manager.delegate = LocationDelegate(continuation: continuation)
        }
        mutating func next() async -> CLLocation? {
            await iterator.next()
        }
    }
    class LocationDelegate: NSObject, CLLocationManagerDelegate {
        let continuation: AsyncStream<CLLocation>.Continuation
        init(continuation: AsyncStream<CLLocation>.Continuation) { self.continuation = continuation }
        func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
            for loc in locations { continuation.yield(loc) }
        }
    }
}

struct LocationView: View {
    @State var location: CLLocation?
    var body: some View {
        Text(location?.description ?? "No location")
            .task {
                for await loc in LocationStream() {
                    location = loc
                }
            }
    }
}

