struct PublisherAsyncSequence<Output, Failure: Error>: AsyncSequence {
    typealias Element = Output
    let publisher: AnyPublisher<Output, Failure>
    func makeAsyncIterator() -> AsyncIterator { AsyncIterator(publisher: publisher) }
    struct AsyncIterator: AsyncIteratorProtocol {
        let publisher: AnyPublisher<Output, Failure>
        var subscription: AnyCancellable?
        let stream: AsyncStream<Output>
        var iterator: AsyncStream<Output>.Iterator
        init(publisher: AnyPublisher<Output, Failure>) {
            var continuation: AsyncStream<Output>.Continuation!
            stream = AsyncStream { c in
                continuation = c
            }
            iterator = stream.makeAsyncIterator()
            subscription = publisher.sink(receiveCompletion: { _ in
                continuation.finish()
            }, receiveValue: { value in
                continuation.yield(value)
            })
        }
        mutating func next() async -> Output? {
            await iterator.next()
        }
    }
}

